    { prompt: "What is 'Space-Time' (Tau) in a continuous reactor?", options: ["Traveling at the speed of light","The volume of the reactor divided by the volumetric flow rate (V/Q); it represents the average time a packet of fluid spends inside the reactor","The time to build the reactor","The physical space the reactor takes up"], answer: 1, difficulty: 1600, timeLimit: 20 },
    { prompt: "According to the Arrhenius Equation, how does Temperature typically affect reaction rate?", options: ["It slows it down","Reaction rate increases exponentially with an increase in absolute temperature","It has no effect","It makes the reaction stop"], answer: 1, difficulty: 1700, timeLimit: 20 },
    { prompt: "What is 'Activation Energy' (Ea)?", options: ["The energy needed to start the factory","The minimum amount of energy required by the reacting molecules to successfully collide and initiate the chemical reaction","The energy released by a bomb","Electrical energy"], answer: 1, difficulty: 1800, timeLimit: 20 },
    { prompt: "A catalyst increases reaction rate by:", options: ["Being consumed as fuel","Providing a lower-activation-energy pathway","Removing heat through the jacket","Increasing mixing blade diameter"], answer: 1, difficulty: 1900, timeLimit: 20 }
