    { prompt: "What is the difference between a 'Static' and 'Dynamic' model?", options: ["Static models are boring","A static model represents a system at a single point in time (like a snapshot in equilibrium); a dynamic model accounts for time-dependent changes in the system state","Dynamic models move physically","Static models are made of plastic"], answer: 1, difficulty: 1200, timeLimit: 20 },
    { prompt: "What is the difference between a 'Deterministic' and 'Stochastic' model?", options: ["Deterministic is for math, Stochastic is for science","A deterministic model has no randomness (same input always gives exact same output); a stochastic model incorporates random variables and probabilities, giving a range of possible outcomes","They mean the same thing","Stochastic is faster"], answer: 1, difficulty: 1300, timeLimit: 20 },
    { prompt: "What is 'Discrete-Event Simulation' (DES)?", options: ["Simulating continuous fluid flow","A modeling approach where the operation of a system is represented as a chronological sequence of distinct, separate 'events' occurring at specific points in time (like customers arriving at a bank)","A simulation of continuous chemical reactions","Simulating the universe"], answer: 1, difficulty: 1400, timeLimit: 20 },
    { prompt: "What is 'Continuous Simulation'?", options: ["Simulating discrete queues","A modeling approach where the state variables change continuously over time, typically represented by a set of differential equations (like simulating the water level in a draining tank)","A simulation that never stops","Simulating a coin flip"], answer: 1, difficulty: 1500, timeLimit: 20 },
    { prompt: "What is the purpose of 'Verification' in modeling?", options: ["Checking if the model works in the real world","Ensuring that the computer program correctly implements the conceptual mathematical model ('Did we build the model right?'); debugging the code","Selling the model","Publishing a paper"], answer: 1, difficulty: 1600, timeLimit: 20 },
    { prompt: "What is the purpose of 'Validation' in modeling?", options: ["Debugging the code","Determining if the model accurately represents the *real-world* system it is intended to simulate ('Did we build the right model?'), usually by comparing simulation output to real experimental data","Making the model look pretty","Getting a patent"], answer: 1, difficulty: 1700, timeLimit: 20 },
    { prompt: "What is a 'Monte Carlo Simulation'?", options: ["A gambling game","A broad class of computational algorithms that rely on repeated random sampling (generating thousands of random scenarios) to obtain numerical results and calculate the probability of different outcomes","Simulating a car race","A simulation using only integers"], answer: 1, difficulty: 1800, timeLimit: 20 },
    { prompt: "What is 'Agent-Based Modeling' (ABM)?", options: ["Modeling chemical agents","A class of computational models for simulating the actions and interactions of autonomous individuals ('agents', like people in a crowd or cells in a tissue) to assess their effects on the system as a whole","Modeling a real estate agent","A type of static model"], answer: 1, difficulty: 1900, timeLimit: 20 }
